SELECT clients.client_name, portfolios.portfolio_name
FROM clients
JOIN portfolios ON clients.client_id = portfolios.client_id;

SELECT manager_name, department
FROM fund_managers
WHERE experience > 10;

SELECT portfolio_name, target_return
FROM portfolios
WHERE target_return > (SELECT AVG(target_return) FROM portfolios);

SELECT report_date
FROM reports
WHERE report_id = 0;

SELECT fund_name, AVG(fund_size) AS average_size
FROM funds
GROUP BY fund_name;

SELECT client_name, email, account_type, address
FROM clients
WHERE client_id = 1;
